import React, { useState } from 'react'; // Kita butuh useState untuk menyimpan input

function Login() {
  // 1. Definisikan State (Gelas untuk menampung input)
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  // 2. Fungsi untuk menangani Login
  const handleLogin = async (e) => {
    e.preventDefault(); // Mencegah halaman reload saat tombol diklik

    try {
      const response = await fetch('http://127.0.0.1:5000/api/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 
          email: email, 
          password: password 
        }),
      });

      const result = await response.json();

      if (response.ok) {
        alert("Login Berhasil! Selamat Datang " + result.user);
        window.location.href = "/dashboard"; // Pindah ke dashboard
      } else {
        alert(result.message); // Menampilkan "Email atau Password Salah"
      }
    } catch (error) {
      alert("Gagal terhubung ke Backend. Pastikan Flask sudah jalan!");
    }
  };

  return (
    <div style={{ padding: '20px', textAlign: 'center' }}>
      <h2>Login Admin Smart Trash</h2>
      <form onSubmit={handleLogin}>
        <div>
          <input 
            type="email" 
            placeholder="Email" 
            value={email} 
            onChange={(e) => setEmail(e.target.value)} // Update isi email
            required 
          />
        </div>
        <br />
        <div>
          <input 
            type="password" 
            placeholder="Password" 
            value={password} 
            onChange={(e) => setPassword(e.target.value)} // Update isi password
            required 
          />
        </div>
        <br />
        <button type="submit">Login</button>
      </form>
    </div>
  );
}

export default Login;
